        /// <summary>Tries to parse a span of characters into a Bits16384.</summary>
        public static bool TryParse(ReadOnlySpan<char> s, IFormatProvider? provider, out Bits16384 result) => TryParse(s.ToString(), provider, out result);

        /// <summary>Parses a string using invariant culture.</summary>
        [MethodImpl(MethodImplOptions.AggressiveInlining)]
