                return s is null ? default : Bits16384.Parse(s);
            }

            /// <summary>Writes a Bits16384 to JSON as a hex string.</summary>
            public override void Write(Utf8JsonWriter writer, Bits16384 value, JsonSerializerOptions options)
            {
                writer.WriteStringValue(value.ToString());
            }
        }

    }
}
